#include <bits/stdc++.h>
using namespace std;
int n,m,dist[20004];
int f,max_dist,sum;
bool b[20004];
queue<int> a;
vector<int> g[20004];
int main(){
    cin>>n>>m;
    for(int i=1;i<=m;i++){
        int u,v;
        cin>>u>>v;
        g[u].push_back(v);
        g[v].push_back(u);
    }
    memset(dist,127,sizeof(dist));
    dist[1]=0,a.push(1),b[1]=1;
    while(a.size()){
        int u=a.front(),len=g[u].size();
        b[u]=false,a.pop();
        for(int i=0;i<len;i++){
            int v=g[u][i];
            if(dist[v]>dist[u]+1){
                dist[v]=dist[u]+1;
                if(!b[v])
                    b[v]=true,a.push(v);
            }
        }
    }
    for(int i=1;i<=n;i++)
        if(dist[i]<(1<<30))max_dist=max(max_dist,dist[i]);
    for(int i=1;i<=n;i++){
        if(dist[i]==max_dist){
            if(!f)
                f=i;
            sum++;
        }
    }
    cout<<f<<' '<<max_dist<<' '<<sum;
    return 0;
}
